CreateEtcdInstance.input:
POST / HTTP/1.1
Host: cetcd.tencentcloudapi.com
Content-Type: application/json
X-TC-Action: CreateEtcdInstance
<公共请求参数>

{
    "Name": "etcd-cluster-1",
    "Description": "examplecluster",
    "VpcId": "vpc-abcd1234",
    "ServiceSubnetId": "subnet-abcd1234",
    "SubnetIds": [
        "subnet-abcd1234"
    ],
    "EtcdVersion": "v3.4.9",
    "Size": 3,
    "AdvancedSettings": {
        "MonitorSettings": {
            "ExistedPrometheusInstanceId": "prom-abcd1234"
        },
        "BackupSettings": {
            "BackupInterval": 300,
            "MaxBackupCount": 5
        }
    },
    "DeletionProtection": true
}

